  options = '[{"id":"A","text":"The train inched across the bridge, its wheels groaning slowly against the steel.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The train moved slowly across the bridge, its progress punctuated by the rhythmic clang of the wheels.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"As the train crossed the bridge, it seemed to be moving at a snail’s pace.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The train was moving slowly across the bridge, but it seemed to be moving quickly.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'Choice A uses the verb "inched" to create a sense of slow, deliberate movement. The phrase "its wheels groaning slowly against the steel" adds to the sense of anticipation and suspense by creating a more vivid and sensory image of the train’s progress. Choices B and C use less vivid language and don’t create the same sense of slowness. Choice D is incorrect because the sentence describes a contradiction, which is illogical in this context. The passage states that "The writer of a memoir is describing an event where a train is traveling across a bridge. The writer wants to emphasize …", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: The train inched across the bridge, its wheels groaning slowly against the steel.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":992,"opensat_domain":"Standard English Conventions","opensat_raw_id":"3452f782","opensat_difficulty":"Medium","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.914Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
